import React from 'react';
import './App.css';

function App() {
  return (
   <div className='form-page'>
    <div className='form-container'>
    <h2>Enter Details</h2>
    <form className='form'>
      <div className='field'>
        <label className='label'>Name</label><br />
         <input type='text' placeholder='Name' className='form-input' />
      </div>
    </form>
   </div>
   </div>
  );
}

export default App;
